export interface AnimatedBeamProps {
	class?: string;
	containerRef: HTMLElement | null;
	fromRef: HTMLElement | null;
	toRef: HTMLElement | null;
	curvature?: number;
	reverse?: boolean;
	pathColor?: string;
	pathWidth?: number;
	pathOpacity?: number;
	gradientStartColor?: string;
	gradientStopColor?: string;
	delay?: number;
	duration?: number;
	startXOffset?: number;
	startYOffset?: number;
	endXOffset?: number;
	endYOffset?: number;
}

export interface PathDimensions {
	width: number;
	height: number;
}

export interface GradientCoordinates {
	x1: string[];
	x2: string[];
	y1: string[];
	y2: string[];
}

import type { GradientCoordinates } from "./types";

export function useGradientCoordinates(reverse: boolean): GradientCoordinates {
	return reverse
		? {
				x1: ["90%", "-10%"],
				x2: ["100%", "0%"],
				y1: ["0%", "0%"],
				y2: ["0%", "0%"],
			}
		: {
				x1: ["10%", "110%"],
				x2: ["0%", "100%"],
				y1: ["0%", "0%"],
				y2: ["0%", "0%"],
			};
}

import type { PathDimensions } from "./types";

export function usePathCalculator() {
	let pathD = $state("");
	let svgDimensions = $state<PathDimensions>({ width: 0, height: 0 });

	function calculatePath(
		containerRef: HTMLElement | null,
		fromRef: HTMLElement | null,
		toRef: HTMLElement | null,
		curvature: number,
		startXOffset: number,
		startYOffset: number,
		endXOffset: number,
		endYOffset: number
	) {
		if (!containerRef || !fromRef || !toRef) return;

		const containerRect = containerRef.getBoundingClientRect();
		const rectA = fromRef.getBoundingClientRect();
		const rectB = toRef.getBoundingClientRect();

		const svgWidth = containerRect.width;
		const svgHeight = containerRect.height;
		svgDimensions = { width: svgWidth, height: svgHeight };

		const startX = rectA.left - containerRect.left + rectA.width / 2 + startXOffset;
		const startY = rectA.top - containerRect.top + rectA.height / 2 + startYOffset;
		const endX = rectB.left - containerRect.left + rectB.width / 2 + endXOffset;
		const endY = rectB.top - containerRect.top + rectB.height / 2 + endYOffset;

		const controlY = startY - curvature;
		const d = `M ${startX},${startY} Q ${(startX + endX) / 2},${controlY} ${endX},${endY}`;
		pathD = d;
	}

	return {
		get pathD() {
			return pathD;
		},
		get svgDimensions() {
			return svgDimensions;
		},
		calculatePath,
	};
}

import { onMount } from "svelte";

export function useResizeObserver(getContainerRef: () => HTMLElement | null, callback: () => void) {
	onMount(() => {
		const containerRef = getContainerRef();
		if (!containerRef) return;

		const resizeObserver = new ResizeObserver(() => {
			callback();
		});

		resizeObserver.observe(containerRef);

		// Initial call
		callback();

		return () => {
			resizeObserver.disconnect();
		};
	});
}
